"""de Boer / Rafi MPRA construct scaffold.

The 5,000 bp plasmid construct used in the de Boer 2020 random-promoter
MPRA.  The variable region (110 bp: 17 bp polyT overhang + 80 bp random +
13 bp polyA overhang) is inserted between polyT_no_overhang and
polyA_no_overhang.  The overhangs are already present in the 110 bp
sequence from the experiment — they are NOT duplicated.

Scaffold constants copied verbatim from
``archive/deboer/dataset.py::PromoterDataset``.
"""

UPSTREAM_POLYT_777BP = ""
POLYT_NO_OVERHANG = "gctagcaggaatgatgcaaaaggttcccgattcgaac"
POLYA_NO_OVERHANG = "tcttaattaaaaaaagatagaaaacattaggagtgtaacacaagactttcggatcctgagcaggcaagataaacga"
YFP_CONNECTOR = "aggcaaag"
YFP = ""
YFP_TERM_CONNECTOR = "ggcgcgccacttctaaataa"
ADH1_TERMINATOR = "gcgaatttcttatgatttatgatttttattattaaataagttataaaaaaaataagtgtatacaaattttaaagtgactcttaggttttaaaacgaaaattcttattcttgagtaactctttcctgtaggtcaggttgctttctcaggtatagtatgaggtcgctcttattgaccacacctctaccgg"
TERM_NATMX6_CONNECTOR = "cagatccgctagggataacagggtaatatagatctgtttagcttgcctcgtccccgccgggtcacccggccagc"
NATMX6 = ""
NATMX6_CEN_CONNECTOR = "ctgtcgattcgatactaacgccgccatccagtgtcgaaaacgagctcgaattcctgggtccttttc"
CEN = ""
CEN_DOWNSTREAM = ""

POLYT_OVERHANG = "TGCATTTTTTTCACATC".lower()
POLYA_OVERHANG = "GGTTACGGCTGTT".lower()

# Pre-computed scaffold prefix and suffix (everything except the variable
# 110 bp region).  Concatenating prefix + variable_110bp + suffix gives
# the full 5,000 bp construct.
_PREFIX = UPSTREAM_POLYT_777BP + POLYT_NO_OVERHANG  # 814 bp
_SUFFIX = (
    POLYA_NO_OVERHANG
    + YFP_CONNECTOR
    + YFP
    + YFP_TERM_CONNECTOR
    + ADH1_TERMINATOR
    + TERM_NATMX6_CONNECTOR
    + NATMX6
    + NATMX6_CEN_CONNECTOR
    + CEN
    + CEN_DOWNSTREAM
)  # 4076 bp

assert len(_PREFIX) == 814
assert len(_SUFFIX) == 4076
assert len(_PREFIX) + 110 + len(_SUFFIX) == 5000

# YFP CDS position within the 5,000 bp construct (0-indexed).
YFP_START = len(_PREFIX) + 110 + len(POLYA_NO_OVERHANG) + len(YFP_CONNECTOR)  # 1008
YFP_END = YFP_START + len(YFP)  # 1725

assert YFP_START == 1008
assert YFP_END == 1725


def build_construct(seq_110bp: str) -> str:
    """Embed a 110 bp MPRA sequence into the 5,000 bp plasmid construct.

    The 110 bp sequence already contains the polyT (17 bp) and polyA
    (13 bp) overhangs — the scaffold's ``polyT_no_overhang`` and
    ``polyA_no_overhang`` are the flanking regions *outside* those
    overhangs, so nothing is duplicated.
    """
    seq = seq_110bp.lower()
    assert len(seq) == 110, f"expected 110 bp, got {len(seq)}"
    assert seq.startswith(POLYT_OVERHANG), "sequence does not start with polyT overhang"
    assert seq.endswith(POLYA_OVERHANG), "sequence does not end with polyA overhang"
    construct = _PREFIX + seq + _SUFFIX
    assert len(construct) == 5000
    return construct
